using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // EF Core 9 renamed "Discriminator" to "$type". Revert to keep
            // compatibility with existing 500K documents and direct SQL queries.
            entity.HasDiscriminator<string>("Discriminator");

            // EF Core 9 changed id format from "Product|123" to "Product-123".
            // Use the legacy format so existing documents remain readable.
            entity.HasIdSeparator('|');

            entity.HasIndex(p => p.Sku);
        });
    }
}
