using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1: EF Core 9 renamed "Discriminator" to "$type".
            // Revert to keep compat with existing documents and direct SQL queries.
            entity.HasDiscriminator<string>("Discriminator");

            // BREAKING CHANGE 2: EF Core 9 changed id format from "TypeName|Key"
            // to "TypeName-Key" and may skip the discriminator prefix entirely for
            // non-hierarchical types. Use HasShadowId(true) to preserve __id behavior,
            // and map it with the legacy "|" separator via a value generator.
            entity.HasShadowId(true);

            // Configure the shadow __id property to use the legacy format.
            entity.Property<string>("__id")
                .HasValueGenerator<LegacyCosmosIdGenerator>();

            entity.HasIndex(p => p.Sku);
        });
    }
}

class Product { public int Id { get; set; } public string Sku { get; set; } }

/// <summary>
/// Generates Cosmos id values in the EF Core 8 format: "Product|{key}"
/// so that existing 500K documents remain accessible.
/// </summary>
class LegacyCosmosIdGenerator : Microsoft.EntityFrameworkCore.ValueGeneration.ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;
    protected override string GenerateNonTemporaryValue(
